#include "interface.h"
#include <cstdint>
#include <vector>
#include <omp.h>

namespace {

uint64_t checksum_u32(const std::vector<uint32_t>& data) {
  uint64_t hash = 1469598103934665603ULL;
  for (uint32_t v : data) {
    hash ^= static_cast<uint64_t>(v);
    hash *= 1099511628211ULL;
  }
  return hash;
}

} // namespace

uint64_t jacobi_checksum(const std::vector<uint32_t>& input, int rows, int cols, int steps) {
  if (rows <= 0 || cols <= 0) return 0;

  std::vector<uint32_t> a = input;
  std::vector<uint32_t> b(a.size(), 0);

  // Pre-copy boundaries to b to ensure they remain constant
  // However, the logic says b[idx] = a[idx] for boundaries.
  // Since we swap, we must ensure boundaries are always copied.

  const std::size_t n = static_cast<std::size_t>(rows) * static_cast<std::size_t>(cols);
  const std::size_t c_size = static_cast<std::size_t>(cols);

  for (int step = 0; step < steps; ++step) {
    #pragma omp parallel
    {
      // Handle boundaries and interior separately to avoid branching in the hot loop
      // 1. Handle top and bottom rows
      #pragma omp for
      for (int col = 0; col < cols; ++col) {
        b[col] = a[col]; // Top row
        b[static_cast<std::size_t>(rows - 1) * c_size + col] = a[static_cast<std::size_t>(rows - 1) * c_size + col]; // Bottom row
      }

      // 2. Handle left and right columns for middle rows
      #pragma omp for
      for (int row = 1; row < rows - 1; ++row) {
        b[static_cast<std::size_t>(row) * c_size] = a[static_cast<std::size_t>(row) * c_size]; // Left col
        b[static_cast<std::size_t>(row) * c_size + (cols - 1)] = a[static_cast<std::size_t>(row) * c_size + (cols - 1)]; // Right col
      }

      // 3. Main computational kernel (Interior)
      #pragma omp for schedule(static)
      for (int row = 1; row < rows - 1; ++row) {
        const std::size_t row_offset = static_cast<std::size_t>(row) * c_size;
        for (int col = 1; col < cols - 1; ++col) {
          const std::size_t idx = row_offset + col;
          b[idx] = (a[idx] * 4u + a[idx - 1] + a[idx + 1] + 
                    a[idx - c_size] + a[idx + c_size]) / 8u;
        }
      }
    }
    a.swap(b);
  }

  return checksum_u32(a);
}
